INSERT INTO `wp_posts` VALUES (70,1,'2026-06-30 08:52:00','2026-06-30 08:52:00','<!-- wp:group {\"tagName\":\"header\",\"className\":\"wg-top-header\",\"layout\":{\"type\":\"default\"}} -->\n<header class=\"wp-block-group wg-top-header\"><!-- wp:group {\"className\":\"wg-header-left\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group wg-header-left\"><!-- wp:html -->\n<button id=\"wg-toggle-sidebar\" class=\"wg-icon-button wg-btn-toggle-sidebar\">\n            <svg viewBox=\"0 -960 960 960\" xmlns=\"http://www.w3.org/2000/svg\" class=\"wg-sidebar-toggle-svg\">\n                <path d=\"M140.001-260.001v-45.384h488.46v45.384h-488.46Zm647.998-47L613.616-480.615l173.768-172.999L819.999-621 678.845-480.615l141.769 140.999-32.615 32.615ZM140.001-458.924v-45.383h371.537v45.383H140.001Zm0-195.691v-45.384h488.46v45.384h-488.46Z\" stroke-linecap=\"round\"></path>\n            </svg>\n        </button>\n<!-- /wp:html -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group\"><!-- wp:site-logo {\"width\":148} /-->\n\n<!-- wp:site-title {\"level\":0,\"style\":{\"typography\":{\"fontSize\":\"20px\",\"fontWeight\":\"700\"},\"elements\":{\"link\":{\"color\":{\"text\":\"#ffffff\"}}}}} /--></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"wg-header-center\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group wg-header-center\"><!-- wp:html -->\n<form role=\"search\" method=\"get\" action=\"/\" class=\"wp-block-search__button-outside wp-block-search__icon-button wp-block-search\" style=\"width: 100%;\">\n            <label class=\"wp-block-search__label screen-reader-text\">Search</label>\n            <div class=\"wp-block-search__inside-wrapper\">\n                <input type=\"search\" class=\"wp-block-search__input wg-header-search-input\" name=\"s\" placeholder=\"Search games...\" required=\"\">\n                <input type=\"hidden\" name=\"post_type\" value=\"game\">\n                <button type=\"submit\" class=\"wp-block-search__button has-icon\" aria-label=\"Search\">\n                    <svg class=\"search-icon\" viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M13 5c-3.3 0-6 2.7-6 6 0 1.4.5 2.7 1.3 3.7l-3.8 3.8 1.1 1.1 3.8-3.8c1 .8 2.3 1.3 3.7 1.3 3.3 0 6-2.7 6-6S16.3 5 13 5zm0 10.5c-2.5 0-4.5-2-4.5-4.5s2-4.5 4.5-4.5 4.5 2 4.5 4.5-2 4.5-4.5 4.5z\"></path></svg>\n                </button>\n            </div>\n        </form>\n<!-- /wp:html --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"wg-header-right\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group wg-header-right\"><!-- wp:html -->\n<!-- Mobile search toggle -->\n        <button id=\"wg-mobile-search-btn\" class=\"wg-icon-button wg-mobile-search-toggle\" aria-label=\"Toggle Search\">\n            <svg class=\"search-icon\" viewBox=\"0 0 24 24\" width=\"24\" height=\"24\" fill=\"currentColor\"><path d=\"M13 5c-3.3 0-6 2.7-6 6 0 1.4.5 2.7 1.3 3.7l-3.8 3.8 1.1 1.1 3.8-3.8c1 .8 2.3 1.3 3.7 1.3 3.3 0 6-2.7 6-6S16.3 5 13 5zm0 10.5c-2.5 0-4.5-2-4.5-4.5s2-4.5 4.5-4.5 4.5 2 4.5 4.5-2 4.5-4.5 4.5z\"></path></svg>\n        </button>\n<!-- /wp:html -->\n\n<!-- wp:html -->\n<a href=\"/favorite-games/\" title=\"Favorites\" class=\"wg-icon-button wg-fav-button-wrapper\">\n            <span class=\"dashicons dashicons-heart\"></span>\n            <span class=\"wg-fav-count\" style=\"display:none;\">0</span>\n        </a>\n<!-- /wp:html -->\n\n<!-- wp:group {\"className\":\"wg-header-user-wrapper\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group wg-header-user-wrapper\"><!-- wp:shortcode -->\n[webgames_header_user]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:html -->\n<!-- Mobile Search Overlay -->\n    <div id=\"wg-mobile-search-overlay\" class=\"wg-mobile-search-overlay\">\n        <form role=\"search\" method=\"get\" action=\"/\" class=\"wp-block-search__button-outside wp-block-search__icon-button wp-block-search\">\n            <label class=\"wp-block-search__label screen-reader-text\">Search</label>\n            <div class=\"wp-block-search__inside-wrapper\">\n                <input type=\"search\" class=\"wp-block-search__input wg-header-search-input\" name=\"s\" placeholder=\"Search games...\" required=\"\">\n                <input type=\"hidden\" name=\"post_type\" value=\"game\">\n                <button type=\"submit\" class=\"wp-block-search__button has-icon\" aria-label=\"Search\">\n                    <svg class=\"search-icon\" viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M13 5c-3.3 0-6 2.7-6 6 0 1.4.5 2.7 1.3 3.7l-3.8 3.8 1.1 1.1 3.8-3.8c1 .8 2.3 1.3 3.7 1.3 3.3 0 6-2.7 6-6S16.3 5 13 5zm0 10.5c-2.5 0-4.5-2-4.5-4.5s2-4.5 4.5-4.5 4.5 2 4.5 4.5-2 4.5-4.5 4.5z\"></path></svg>\n                </button>\n            </div>\n        </form>\n        <button id=\"wg-close-mobile-search\" class=\"wg-icon-button wg-mobile-search-close\" aria-label=\"Close Search\">\n            <span class=\"dashicons dashicons-no-alt\"></span>\n        </button>\n    </div>\n\n    <script>\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            var urlParams = new URLSearchParams(window.location.search);\n            var q = urlParams.get(\'s\');\n            if (q) {\n                var inputs = document.querySelectorAll(\'.wg-header-search-input\');\n                inputs.forEach(function(input) { input.value = q; });\n            }\n\n            // Mobile search overlay toggle\n            var mobileSearchBtn = document.getElementById(\'wg-mobile-search-btn\');\n            var closeSearchBtn = document.getElementById(\'wg-close-mobile-search\');\n            var searchOverlay = document.getElementById(\'wg-mobile-search-overlay\');\n\n            if (mobileSearchBtn && searchOverlay) {\n                mobileSearchBtn.addEventListener(\'click\', function() {\n                    searchOverlay.classList.add(\'is-active\');\n                    var input = searchOverlay.querySelector(\'input[type=\"search\"]\');\n                    if(input) input.focus();\n                });\n            }\n\n            if (closeSearchBtn && searchOverlay) {\n                closeSearchBtn.addEventListener(\'click\', function() {\n                    searchOverlay.classList.remove(\'is-active\');\n                });\n            }\n        });\n    </script>\n<!-- /wp:html --></header>\n<!-- /wp:group -->','Header','','publish','closed','closed','','header','','','2026-06-30 08:52:00','2026-06-30 08:52:00','',0,'https://miniwebgames.local/header/',0,'wp_template_part','',0);
INSERT INTO `wp_posts` VALUES (71,1,'2026-06-30 09:16:14','2026-06-30 09:16:14','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Welcome to MiniWebGames.com!</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Our Mission </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">At MiniWebGames, we believe that entertainment should be instant, relaxing, and accessible to everyone. In a world full of complex gaming setups and endless app downloads, our mission is simple: to provide a clean, lightning-fast platform where you can enjoy high-quality browser games with just a single click. Whether you are looking for a quick brain workout during your lunch break or a relaxing melodic journey after a long day, you have found the right place.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">What We Offer: A Hub of Interactive Entertainment </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Our platform features a carefully curated and constantly growing collection of HTML5 games, designed for players of all skill levels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">A core highlight of our catalog is our <strong>Music Games</strong> hub. We celebrate the colorful world of rhythm and sound through interactive browser experiences. From fast-paced beat challenges that test your reaction speed to relaxing melody creation tools, we gather music-focused entertainment for everyone. You can immerse yourself in rhythm games with synchronized patterns, explore music-creation tools for custom sound combinations, or enjoy instrument simulators—all bringing an energetic and creative atmosphere directly to your screen.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Beyond music, our library is continuously expanding with fresh adventures, classic puzzles, and innovative indie projects to ensure every visit offers something new to discover.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">The Power of HTML5: Play Instantly, Everywhere </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We leverage the true power of modern HTML5 technology to put the player first. What does this mean for you?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Zero Downloads:</strong> There is no need to endure long waiting times or apply through app stores. Click a game, and the fun begins instantly.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Cross-Device Compatibility:</strong> Whether you are browsing on a classic desktop, a macOS laptop, a tablet, or a smartphone, our games adapt flawlessly to your screen.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Lightweight Performance:</strong> Hosted on high-speed servers, our games ensure smooth controls, fast load times, and responsive gameplay across all modern browsers.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Our Promise to You </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We are committed to maintaining a user-friendly environment. Our team frequently updates the game collections, introduces seasonal events, and ensures simple navigation for faster discovery. We focus on catchy soundtracks, vibrant visuals, and, most importantly, a safe and enjoyable web experience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Get in Touch </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your feedback helps us grow! If you have any questions, suggestions, or just want to say hello, feel free to reach out to us at: <strong>thanhlong.bkpro@.com</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Join the fascinating world of MiniWebGames today. It’s time to explore new sounds, challenge your reflexes, and discover exciting digital worlds right now!</p>\n<!-- /wp:paragraph -->','About Us','','publish','closed','closed','','about-us','','','2026-07-08 02:09:34','2026-07-08 02:09:34','',0,'https://miniwebgames.local/?page_id=71',0,'page','',0);
INSERT INTO `wp_posts` VALUES (72,1,'2026-06-30 09:16:14','2026-06-30 09:16:14','<!-- wp:paragraph -->\n<p>About Us</p>\n<!-- /wp:paragraph -->','About Us','','inherit','closed','closed','','71-revision-v1','','','2026-06-30 09:16:14','2026-06-30 09:16:14','',71,'https://miniwebgames.local/?p=72',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (73,1,'2026-06-30 09:16:26','2026-06-30 09:16:26','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">We\'d Love to Hear From You!</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Whether you need assistance, have a suggestion for a new game, or just want to share your feedback about our platform, our team is always ready to help. At MiniWebGames, we are committed to providing you with the best, interruption-free gaming experience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Reach Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email Support:</strong> For general inquiries, technical support, or partnership proposals, please drop us a line at <strong>thanhlong.bkpro@gmail.com</strong>. We make every effort to review all emails and reply within 24-48 business hours.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Connect With Us:</strong> Want to see our latest game updates, high-score challenges, or relaxing gameplay videos? Join our growing community on our social channels:<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Youtube: <a href=\"https://www.youtube.com/@miniwebgames\">https://www.youtube.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Facebook: <a href=\"https://www.facebook.com/profile.php?id=61591336000883\">https://www.facebook.com/profile.php?id=61591336000883</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Instagram: <a href=\"https://www.instagram.com/miniwebgames/\">https://www.instagram.com/miniwebgames/</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Threads: <a href=\"https://www.threads.com/@miniwebgames\">https://www.threads.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Tiktok: <a href=\"https://www.tiktok.com/@miniwebgames\">https://www.tiktok.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>X (Twitter): <a href=\"https://x.com/MiniWebGames\">https://x.com/MiniWebGames</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Send Us a Message directly </h3>\n<!-- /wp:heading -->\n\n<!-- wp:shortcode -->\n[contact-form-7 id=\"f02882b\" title=\"Contact Form\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Important Note for Users: </strong>We value your privacy. Any information you submit through this form or via email will strictly be used to assist you and will not be shared with third parties.</p>\n<!-- /wp:paragraph -->','Contact Us','','publish','closed','closed','','contact-us','','','2026-07-08 02:22:57','2026-07-08 02:22:57','',0,'https://miniwebgames.local/?page_id=73',0,'page','',0);
