INSERT INTO `wp_posts` VALUES (80,1,'2026-06-30 09:18:41','2026-06-30 09:18:41','<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Cookie Policy explains how we use cookies and similar technologies on <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By using our Website, you agree to our use of cookies as described in this Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. What Are Cookies?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Cookies are small text files stored on your device when you visit a website. They help websites function properly, remember your preferences, improve performance, and support analytics and advertising.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. How We Use Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use cookies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Save favorite games.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Measure website traffic.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Detect security issues.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Deliver and measure advertisements.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Types of Cookies We Use</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Essential Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These cookies are required for the Website to function properly, including user authentication, account management, and security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Preference Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These cookies remember your settings and preferences to improve your browsing experience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Analytics Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use Google Analytics to understand how visitors interact with our Website and improve our content and services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Advertising Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may use Google AdSense and other advertising partners to display relevant advertisements and measure advertising performance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These providers may use cookies or similar technologies in accordance with their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Third-Party Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Some games, embedded content, social login services, and other third-party features may set their own cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not control these cookies and recommend reviewing the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Managing Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Most web browsers allow you to manage, block, or delete cookies through browser settings.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Disabling certain cookies may affect some features of the Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Updates to This Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may update this Cookie Policy from time to time.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Any changes will be posted on this page with a revised <strong>Effective Date</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">6. Contact Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you have any questions about this Cookie Policy, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h5>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\"><strong>Last Updated:</strong> July 8, 2026</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Cookie Policy','','publish','closed','closed','','cookie-policy','','','2026-07-08 04:29:36','2026-07-08 04:29:36','',0,'https://miniwebgames.local/?page_id=80',0,'page','',0);
INSERT INTO `wp_posts` VALUES (81,1,'2026-06-30 09:18:41','2026-06-30 09:18:41','<!-- wp:paragraph -->\n<p>Cookie Policy</p>\n<!-- /wp:paragraph -->','Cookie Policy','','inherit','closed','closed','','80-revision-v1','','','2026-06-30 09:18:41','2026-06-30 09:18:41','',80,'https://miniwebgames.local/?p=81',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (82,1,'2026-06-30 09:19:00','2026-06-30 09:19:00','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Overview and Safe Harbor</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames.com (‘we’, ‘us’, or ‘our’) respects the intellectual property rights of others and expects users of our platform to do the same. In accordance with the Digital Millennium Copyright Act of 1998 (‘DMCA’), 17 U.S.C. § 512, MiniWebGames.com operates under the notice-and-takedown framework and seeks to qualify for the safe harbor protections set forth in DMCA § 512(c).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We will act expeditiously to remove or disable access to content that is claimed to be infringing upon receipt of a valid DMCA notice as described in this policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Designated Copyright Agent</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">To submit a DMCA takedown notice or counter-notice, please contact our designated copyright agent:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>DMCA Agent:</strong> MiniWebGames.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email:</strong> thanhlong.bkpro@gmail.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Subject Line:</strong> DMCA Takedown Notice</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Filing a Copyright Infringement Notice (Takedown)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you believe that material on MiniWebGames.com’s platform infringes your copyright, you may submit a written notice to the designated agent above. To be valid under DMCA § 512(c)(3), your notice must include all of the following:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your physical or electronic signature, as the owner of an exclusive right that is allegedly infringed, or as an authorized representative of such owner.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the copyrighted work(s) you claim have been infringed. If multiple works are covered by a single notification, please provide a representative list.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the specific material claimed to be infringing, with information reasonably sufficient to permit us to locate it on the platform (e.g., URL, page title, or description).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your contact information, including your full name, mailing address, telephone number, and email address.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement that you have a good faith belief that use of the material in the manner complained of is not authorized by the copyright owner, its agent, or the law.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement, made under penalty of perjury, that the information in the notification is accurate and that you are the copyright owner or are authorized to act on behalf of the owner.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Warning:</strong> Submitting a knowingly false DMCA notice is a federal offense under 17 U.S.C. § 512(f) and may expose you to civil liability for damages, attorney’s fees, and costs.</p>\n<!-- /wp:paragraph --></blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Processing Time</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Upon receipt of a valid and complete DMCA notice, MiniWebGames.com will review and process the claim within <strong>three (3) to five (5) business days</strong>. We will notify the affected user and remove or disable access to the allegedly infringing content pending resolution. Complex or high-volume claims may require additional time.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Counter-Notice Procedure</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If content you uploaded was removed or disabled as a result of a DMCA takedown notice and you believe the removal was made in error or misidentification, you may submit a written counter-notice pursuant to DMCA § 512(g)(3). Your counter-notice must include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your physical or electronic signature.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the material that was removed or disabled, and the location at which it appeared before removal.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement under penalty of perjury that you have a good faith belief that the material was removed or disabled as a result of mistake or misidentification.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your full name, mailing address, telephone number, and email address.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement consenting to the jurisdiction of the Federal District Court for the judicial district in which your address is located (or, if outside the United States, any judicial district in which MiniWebGames.com may be found), and that you will accept service of process from the person who filed the original DMCA notice.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Upon rec<sup></sup>eipt of a valid counter-notice, MiniWebGames.com will forward it to the original complainant. If the complainant does not initiate a court action within <strong>ten (10) business days</strong>, the removed content may be restored at our discretion.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Repeat Infringer Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">In accordance with DMCA § 512(i)(1)(A), MiniWebGames.com maintains a policy of terminating, in appropriate circumstances, the accounts of users who are determined to be repeat infringers. A user who receives <strong>three (3) or more</strong> substantiated copyright infringement notices may have their account suspended or permanently terminated at the sole discretion of MiniWebGames.com. We reserve the right to act sooner in cases of serious or willful infringement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Disclaimer</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This DMCA Policy does not constitute legal advice. MiniWebGames.com recommends consulting a qualified attorney before submitting a takedown notice or counter-notice. The rights and remedies available under the DMCA are in addition to any other rights and remedies available under applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Contact</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">For questions or concerns regarding this policy, please contact:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email:</strong> thanhlong.bkpro@gmail.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Website:</strong> <a href=\"https://miniwebgames.com\" target=\"_blank\" rel=\"noreferrer noopener\">https://miniwebgames.com</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->','DMCA','','publish','closed','closed','','dmca','','','2026-07-08 03:48:46','2026-07-08 03:48:46','',0,'https://miniwebgames.local/?page_id=82',0,'page','',0);
