INSERT INTO `wp_posts` VALUES (134,1,'2026-07-02 07:17:08','2026-07-02 07:17:08','','music','','inherit','open','closed','','music','','','2026-07-02 07:17:08','2026-07-02 07:17:08','',0,'https://miniwebgames.local/wp-content/uploads/2026/07/music.png',0,'attachment','image/png',0);
INSERT INTO `wp_posts` VALUES (137,1,'2026-07-02 08:01:11','2026-07-02 08:01:11','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Sprunki Game - Play Free Online Music Creation Game</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Introduction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Sprunki Game</strong> is a creative browser-based music game where every sound you choose becomes part of an original song. Instead of chasing high scores or defeating enemies, you\'ll build rhythmic compositions by mixing beats, melodies, vocals, and effects. With two distinct themes—including a darker horror-inspired mode—the game encourages experimentation and rewards creativity, making every session sound completely different from the last.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Overview</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Category</th><th>Details</th></tr></thead><tbody><tr><td><strong>Genre</strong></td><td>Music, Rhythm, Creative, Casual</td></tr><tr><td><strong>Platform</strong></td><td>Web Browser (HTML5)</td></tr><tr><td><strong>Gameplay</strong></td><td>Drag and combine sound icons to create custom music tracks</td></tr><tr><td><strong>Main Objective</strong></td><td>Mix different character sounds to compose unique songs and discover new musical combinations</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Play</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki transforms music creation into an interactive game. Every character represents a unique sound element, such as percussion, melody, vocals, or special effects. Drag a sound icon onto a character to activate it, then continue adding more performers until your mix feels complete.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Up to seven sounds can play together at once, allowing you to create anything from simple rhythms to layered musical arrangements. There is no correct order, no required combinations, and no time pressure. Experimenting with different sound sets is the heart of the gameplay.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The game also features two different musical styles:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Normal Mode</strong> offers colorful visuals and upbeat sounds for cheerful compositions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Horror Mode</strong> changes the atmosphere completely with eerie visuals, distorted effects, and unsettling audio that creates darker musical pieces.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can mute individual performers, replace sounds, or rebuild your composition whenever inspiration strikes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Controls</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>PC</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mouse:</strong> Drag and drop sound icons onto characters</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Left Click:</strong> Activate, remove, or swap sounds</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Mobile</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Tap and drag sound icons</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Tap characters to change or remove sounds</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">No keyboard controls are required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Features</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Create unlimited original music combinations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Two completely different themes: Normal and Horror.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Mix beats, melodies, vocals, and sound effects freely.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Simple drag-and-drop controls suitable for all skill levels.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Instantly edit your composition without restarting.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Distinctive characters with their own musical identities.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Relaxing gameplay with no timers or failure conditions.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tips &amp; Tricks</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Begin with a beat before adding melodies and vocals for a balanced track.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Test unexpected character combinations—you may discover your favorite sound.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Use the mute feature to highlight specific instruments during your mix.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Try using fewer active characters to create cleaner, more memorable rhythms.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Switch to Horror Mode for entirely different audio textures and creative inspiration.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Why You\'ll Love This Game</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki stands out because it treats every player like a music producer rather than a competitor. The open-ended design means there are countless ways to build songs, and every combination produces something unique. Whether you enjoy relaxing creativity or experimenting with unusual soundscapes, it\'s easy to lose yourself while creating your own musical style.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Similar Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you enjoy Sprunki, you may also like:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Incredibox</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Friday Night Funkin\'</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Phase 5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Snow Day</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">FAQ</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Is Sprunki free to play?</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Yes. Sprunki can be played directly in your browser without purchasing the game.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Do I need musical experience?</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Not at all. The interface is designed so anyone can create enjoyable music through simple drag-and-drop actions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">What is the difference between Normal Mode and Horror Mode?</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Normal Mode focuses on upbeat visuals and cheerful sounds, while Horror Mode replaces them with darker graphics and haunting audio effects.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Can I replay the game with different results?</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Absolutely. Since you can mix sounds in countless ways, every session can produce a completely different musical composition.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki is a refreshing music creation game that blends creativity with simple gameplay. Instead of following strict objectives, you\'re encouraged to experiment with sounds and discover your own musical ideas. With colorful visuals, a spooky alternate mode, and endless combinations to explore, it\'s an enjoyable browser game for anyone who loves interactive music.</p>\n<!-- /wp:paragraph -->','Sprunki Game Original','','publish','open','closed','','sprunki-game','','','2026-07-03 01:26:43','2026-07-03 01:26:43','',0,'https://miniwebgames.local/?post_type=game&#038;p=137',0,'game','',0);
INSERT INTO `wp_posts` VALUES (138,1,'2026-07-02 07:49:57','2026-07-02 07:49:57','','Sprunki Game','','inherit','open','closed','','sprunki-game-2','','','2026-07-03 01:26:43','2026-07-03 01:26:43','',137,'https://miniwebgames.local/wp-content/uploads/2026/07/sprunki-game.jpg',0,'attachment','image/jpeg',0);
INSERT INTO `wp_posts` VALUES (146,1,'2026-07-03 01:35:11','2026-07-03 01:35:11','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Introduction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Chilly Guy: Sprunki</strong> blends relaxing music creation with light progression, making every session both calming and rewarding. As you build rhythmic compositions, you\'ll unlock fresh environments and musical styles that transform the atmosphere of the game. Simple controls make it easy to jump in, while the steady flow of new themes and collectibles encourages you to keep experimenting with different sounds and melodies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"id\":150,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://miniwebgames.local/wp-content/uploads/2026/07/chilly-guy-sprunki-2.png\" alt=\"\" class=\"wp-image-150\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">About the Game</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Category</th><th>Details</th></tr></thead><tbody><tr><td><strong>Genre</strong></td><td>Music, Rhythm, Casual, HTML5</td></tr><tr><td><strong>Objective</strong></td><td>Collect hearts to unlock new musical worlds and create enjoyable sound combinations.</td></tr><tr><td><strong>Gameplay</strong></td><td>Interact with characters to produce music, earn hearts, and explore additional themes as you progress.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The adventure begins in a bright grassy landscape filled with cheerful tunes. As you gather hearts, additional music themes become available, introducing new visual settings and different audio styles. Along the way, you can continue experimenting with sounds while discovering new creative possibilities.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Play</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Playing Chilly Guy: Sprunki is straightforward, making it suitable for both casual players and music enthusiasts.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Use your mouse or touchscreen to interact with Chill Guy and the available musical elements. Every successful interaction contributes toward collecting hearts, which serve as the game\'s progression system. As your collection grows, new environments and musical themes become accessible.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Besides unlocking content, the game also lets you capture memorable musical moments to revisit or share later. The main objective is to continue expanding your collection of hearts while creating enjoyable musical arrangements throughout each stage.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Controls</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mouse:</strong> Click interactive elements and characters.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mobile:</strong> Tap the screen to interact.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Features</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Relaxing music gameplay with accessible controls.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Unlockable themes featuring unique visual and audio styles.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Heart collection system that rewards steady progression.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Record your favorite musical moments.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser-based gameplay with no installation required.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tips</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Prioritize actions that generate hearts automatically to unlock new content more quickly.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Playing with headphones makes it easier to appreciate the different layers of each musical arrangement.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Save recordings of your favorite sessions so you can compare different sound combinations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Spend time experimenting with newly unlocked themes, as each offers a distinct musical atmosphere.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Similar Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Game</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Phase 5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Incredibox</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Chilly Guy: Sprunki offers a relaxing alternative to traditional rhythm games by focusing on creativity instead of competition. Unlockable music themes, simple controls, and satisfying progression make it an enjoyable browser game for players who like experimenting with sounds while discovering new musical environments.</p>\n<!-- /wp:paragraph -->','Chilly Guy: Sprunki','','publish','open','closed','','chilly-guy-sprunki','','','2026-07-03 01:37:48','2026-07-03 01:37:48','',0,'https://miniwebgames.local/?post_type=game&#038;p=146',0,'game','',0);
