INSERT INTO `wp_posts` VALUES (151,1,'2026-07-03 01:33:15','2026-07-03 01:33:15','','Chilly Guy: Sprunki','','inherit','open','closed','','chilly-guy-sprunki-3','','','2026-07-03 01:35:11','2026-07-03 01:35:11','',146,'https://miniwebgames.local/wp-content/uploads/2026/07/chilly-guy-sprunki.png',0,'attachment','image/png',0);
INSERT INTO `wp_posts` VALUES (154,1,'2026-07-03 01:44:59','2026-07-03 01:44:59','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Introduction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Sprunki Phase 5</strong> expands the familiar music-mixing formula with fresh locations, collectible progression, and interactive sound design. Every rhythm you create helps unlock new environments, each featuring its own atmosphere and visual style. Instead of following a fixed path, you\'re encouraged to experiment with different sound combinations while gradually opening new areas to explore. The result is a relaxing yet rewarding browser game that keeps every session feeling different.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">About the Game</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Category</th><th>Details</th></tr></thead><tbody><tr><td><strong>Genre</strong></td><td>Music, Rhythm, Casual, HTML5</td></tr><tr><td><strong>Objective</strong></td><td>Create music, collect hearts, and unlock new themed environments.</td></tr><tr><td><strong>Gameplay</strong></td><td>Mix sounds, interact with the guide character, and progress by earning hearts through musical creations.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The game begins in a colorful landscape where every sound contributes to your progress. As your heart collection grows, additional locations become available, introducing darker scenery and entirely new moods. Each environment offers a fresh backdrop for experimenting with musical arrangements without changing the game\'s easy-to-learn mechanics.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Play</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki Phase 5 uses simple point-and-click controls that allow you to focus on creativity instead of complicated mechanics.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Click or tap the available characters and sound elements to build your musical composition. The friendly sun character also provides another way to collect hearts, helping you unlock new stages more quickly. Up to seven sounds can be active simultaneously, giving you plenty of freedom to layer beats, melodies, and effects.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The main objective is to earn enough hearts to access every available theme while creating enjoyable musical mixes. You can also use the built-in photo feature to capture memorable moments from your favorite sessions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Controls</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mouse:</strong> Click characters and interactive objects.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mobile:</strong> Tap the screen to activate sounds and collect hearts.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Features</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Three unlockable environments with distinct visual themes.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Heart-based progression system that rewards continued play.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Layer multiple sounds to create original music.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Built-in snapshot feature for saving memorable moments.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser-based gameplay with quick loading and simple controls.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tips</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Activate multiple sound sources to collect hearts more efficiently.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Interact with the guide character whenever possible for additional progress.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Try different sound combinations before unlocking the next environment to discover unique musical styles.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Capture screenshots of your favorite compositions so you can recreate them later.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Similar Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Game</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Incredibox: Kochari</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Chilly Guy: Sprunki</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki Phase 5 combines creative music-making with steady progression, giving players a reason to keep experimenting long after the first song. Unlockable environments, intuitive controls, and flexible sound mixing make it an enjoyable HTML5 game for anyone who likes rhythm-based creativity without competitive pressure.</p>\n<!-- /wp:paragraph -->','Sprunki Phase 5','','publish','open','closed','','sprunki-phase-5','','','2026-07-03 01:44:59','2026-07-03 01:44:59','',0,'https://miniwebgames.local/?post_type=game&#038;p=154',0,'game','',0);
INSERT INTO `wp_posts` VALUES (155,1,'2026-07-03 01:40:24','2026-07-03 01:40:24','','Sprunki Phase 5','','inherit','open','closed','','sprunki-phase-5-2','','','2026-07-03 01:44:59','2026-07-03 01:44:59','',154,'https://miniwebgames.local/wp-content/uploads/2026/07/sprunki-phase-5-2.png',0,'attachment','image/png',0);
INSERT INTO `wp_posts` VALUES (156,1,'2026-07-03 01:50:22','2026-07-03 01:50:22','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Introduction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Sprunki Parasites</strong> takes the familiar music-mixing gameplay of the Sprunki series and places it inside a bleak, corrupted world. Instead of bright melodies and cheerful visuals, you\'ll create haunting soundtracks surrounded by abandoned landscapes and infected characters. The contrast between creative freedom and unsettling atmosphere gives this browser game a distinct personality, making each musical composition feel like part of a larger story.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">About the Game</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Category</th><th>Details</th></tr></thead><tbody><tr><td><strong>Genre</strong></td><td>Music, Rhythm, Horror, HTML5</td></tr><tr><td><strong>Objective</strong></td><td>Combine character sounds to compose unique tracks while exploring a parasite-ravaged world.</td></tr><tr><td><strong>Gameplay</strong></td><td>Drag sound icons onto characters, layer different audio elements, and experiment with dark musical arrangements.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The game\'s setting revolves around a once-thriving world that has been overtaken by a mysterious parasite. The infection has transformed both the environment and its inhabitants, replacing cheerful performances with eerie vocals, distorted effects, and unsettling rhythms. Every new combination changes the mood of your composition, encouraging creative experimentation.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Play</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki Parasites keeps its controls simple while offering plenty of room for creativity.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Choose a sound from the available collection, then drag it onto one of the characters to activate that audio layer. Each character can hold a single sound at a time, allowing you to build your composition piece by piece. Mix percussion, melodies, vocals, and special effects until you create a soundtrack that matches the game\'s haunting atmosphere.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">For players seeking a more intense experience, Dark Mode introduces even stranger visuals and more chaotic sound combinations, creating an entirely different musical mood.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Controls</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mouse:</strong> Drag and drop sound icons onto characters.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Mobile:</strong> Tap and drag sounds to assign them to performers.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Features</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Dark post-apocalyptic setting with horror-inspired visuals.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Drag-and-drop music creation that is easy to learn.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Distinctive infected characters with unique sound effects.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Optional Dark Mode for an even more unsettling atmosphere.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Endless possibilities for creating original musical compositions.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tips</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Start with rhythmic sounds before adding melodies and effects to build a balanced composition.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Replace individual sounds instead of restarting to quickly test new combinations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Explore Dark Mode after learning the standard sound library to appreciate the dramatic audio changes.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Mix contrasting sound types to create more memorable and layered tracks.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Similar Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Game</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki New Version</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Sprunki Phase 5</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Sprunki Parasites offers a darker take on interactive music creation without changing the accessible gameplay that made the series popular. The unsettling world, eerie soundtrack, and creative freedom combine to deliver a memorable browser game for players who enjoy horror themes and experimental rhythm experiences.</p>\n<!-- /wp:paragraph -->','Sprunki Parasites','','publish','open','closed','','sprunki-parasites','','','2026-07-03 01:50:22','2026-07-03 01:50:22','',0,'https://miniwebgames.local/?post_type=game&#038;p=156',0,'game','',0);
