INSERT INTO `wp_posts` VALUES (175,1,'2026-07-03 02:34:26','2026-07-03 02:34:26','','Sprunki OC','','inherit','open','closed','','sprunki-oc-3','','','2026-07-03 02:37:19','2026-07-03 02:37:19','',173,'https://miniwebgames.local/wp-content/uploads/2026/07/sprunki-oc.png',0,'attachment','image/png',0);
INSERT INTO `wp_posts` VALUES (176,1,'2026-07-03 02:41:52','2026-07-03 02:41:52','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Sprunki Infected: Create Chilling Music in a Haunted Rhythm World</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Introduction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Dark visuals, mysterious characters, and creative beat mixing make <strong>Sprunki Infected</strong> a memorable addition to the Sprunki series. Instead of performing on a cheerful stage, you\'ll compose original tracks inside a world threatened by a strange infection. Every sound you assign changes both the music and the appearance of your performers, turning each session into a unique blend of rhythm, creativity, and horror-inspired storytelling.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">About the Game</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Sprunki Infected</strong> is a casual music creation game that reimagines the classic Sprunki formula with a darker atmosphere. Players experiment with sound loops by arranging musical performers, gradually building original compositions without time limits or scoring systems.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The game features seven playable characters that can be customized using <strong>20 different musical icons</strong>. Each icon represents a distinct rhythm, melody, vocal effect, or instrumental sound. As characters receive new sounds, their appearance changes to match their musical role, creating a lively audiovisual performance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">A haunting setting sets this version apart. Shadowy skies, glowing red scenery, and unsettling animated details create constant tension while still leaving creativity at the center of the gameplay. Rather than fighting enemies directly, players use music to transform the stage and complete their own unique compositions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Play</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Controls</h4>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Use your mouse to drag musical icons onto characters.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Replace or remove sounds at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Experiment with different combinations until you\'re satisfied with your mix.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Gameplay</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Choose sounds from the available collection and assign them to the seven performers on stage. Every added character introduces another musical layer, allowing your composition to grow naturally. Rearrange performers whenever you want to hear fresh rhythms or improve the overall balance of your track.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Because there are no strict objectives or penalties, players are free to experiment as much as they like.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Winning Goal</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The goal is to create an original music mix by combining sounds creatively while exploring the game\'s eerie atmosphere and visual transformations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Features</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Horror-themed environments with dark visual effects</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Twenty unique musical icons for creative mixing</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Seven customizable performers on every stage</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Simple drag-and-drop controls</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Unlimited replay value through endless sound combinations</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tips</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Build a steady rhythm before layering melodies and vocals.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Swap individual sounds instead of changing the entire lineup at once.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Try every musical icon to discover new combinations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Watch how character appearances change as new sounds are assigned.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Replay your favorite arrangements and refine them with small adjustments.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Similar Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sprunki Retake</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sprunki Phase 3</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sprunki Phase 4</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Sprunki Infected</strong> combines music creation with a suspenseful horror setting that feels different from traditional rhythm games. Its flexible gameplay, distinctive visual style, and wide range of sound combinations make it an entertaining browser game for players who enjoy experimenting with original musical creations.</p>\n<!-- /wp:paragraph -->','Sprunki Infected','','publish','open','closed','','sprunki-infected','','','2026-07-03 02:41:52','2026-07-03 02:41:52','',0,'https://miniwebgames.local/?post_type=game&#038;p=176',0,'game','',0);
