INSERT INTO `wp_posts` VALUES (235,1,'2026-07-08 02:22:56','2026-07-08 02:22:56','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">We\'d Love to Hear From You!</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Whether you need assistance, have a suggestion for a new game, or just want to share your feedback about our platform, our team is always ready to help. At MiniWebGames, we are committed to providing you with the best, interruption-free gaming experience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Reach Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email Support:</strong> For general inquiries, technical support, or partnership proposals, please drop us a line at <strong>thanhlong.bkpro@gmail.com</strong>. We make every effort to review all emails and reply within 24-48 business hours.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Connect With Us:</strong> Want to see our latest game updates, high-score challenges, or relaxing gameplay videos? Join our growing community on our social channels:<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Youtube: <a href=\"https://www.youtube.com/@miniwebgames\">https://www.youtube.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Facebook: <a href=\"https://www.facebook.com/profile.php?id=61591336000883\">https://www.facebook.com/profile.php?id=61591336000883</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Instagram: <a href=\"https://www.instagram.com/miniwebgames/\">https://www.instagram.com/miniwebgames/</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Threads: <a href=\"https://www.threads.com/@miniwebgames\">https://www.threads.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Tiktok: <a href=\"https://www.tiktok.com/@miniwebgames\">https://www.tiktok.com/@miniwebgames</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>X (Twitter): <a href=\"https://x.com/MiniWebGames\">https://x.com/MiniWebGames</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Send Us a Message directly </h3>\n<!-- /wp:heading -->\n\n<!-- wp:shortcode -->\n[contact-form-7 id=\"f02882b\" title=\"Contact Form\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Important Note for Users: </strong>We value your privacy. Any information you submit through this form or via email will strictly be used to assist you and will not be shared with third parties.</p>\n<!-- /wp:paragraph -->','Contact Us','','inherit','closed','closed','','73-revision-v1','','','2026-07-08 02:22:56','2026-07-08 02:22:56','',73,'https://miniwebgames.local/?p=235',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (237,1,'2026-07-08 03:48:45','2026-07-08 03:48:45','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Overview and Safe Harbor</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames.com (‘we’, ‘us’, or ‘our’) respects the intellectual property rights of others and expects users of our platform to do the same. In accordance with the Digital Millennium Copyright Act of 1998 (‘DMCA’), 17 U.S.C. § 512, MiniWebGames.com operates under the notice-and-takedown framework and seeks to qualify for the safe harbor protections set forth in DMCA § 512(c).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We will act expeditiously to remove or disable access to content that is claimed to be infringing upon receipt of a valid DMCA notice as described in this policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Designated Copyright Agent</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">To submit a DMCA takedown notice or counter-notice, please contact our designated copyright agent:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>DMCA Agent:</strong> MiniWebGames.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email:</strong> thanhlong.bkpro@gmail.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Subject Line:</strong> DMCA Takedown Notice</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Filing a Copyright Infringement Notice (Takedown)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you believe that material on MiniWebGames.com’s platform infringes your copyright, you may submit a written notice to the designated agent above. To be valid under DMCA § 512(c)(3), your notice must include all of the following:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your physical or electronic signature, as the owner of an exclusive right that is allegedly infringed, or as an authorized representative of such owner.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the copyrighted work(s) you claim have been infringed. If multiple works are covered by a single notification, please provide a representative list.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the specific material claimed to be infringing, with information reasonably sufficient to permit us to locate it on the platform (e.g., URL, page title, or description).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your contact information, including your full name, mailing address, telephone number, and email address.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement that you have a good faith belief that use of the material in the manner complained of is not authorized by the copyright owner, its agent, or the law.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement, made under penalty of perjury, that the information in the notification is accurate and that you are the copyright owner or are authorized to act on behalf of the owner.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Warning:</strong> Submitting a knowingly false DMCA notice is a federal offense under 17 U.S.C. § 512(f) and may expose you to civil liability for damages, attorney’s fees, and costs.</p>\n<!-- /wp:paragraph --></blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Processing Time</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Upon receipt of a valid and complete DMCA notice, MiniWebGames.com will review and process the claim within <strong>three (3) to five (5) business days</strong>. We will notify the affected user and remove or disable access to the allegedly infringing content pending resolution. Complex or high-volume claims may require additional time.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Counter-Notice Procedure</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If content you uploaded was removed or disabled as a result of a DMCA takedown notice and you believe the removal was made in error or misidentification, you may submit a written counter-notice pursuant to DMCA § 512(g)(3). Your counter-notice must include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your physical or electronic signature.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Identification of the material that was removed or disabled, and the location at which it appeared before removal.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement under penalty of perjury that you have a good faith belief that the material was removed or disabled as a result of mistake or misidentification.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Your full name, mailing address, telephone number, and email address.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">A statement consenting to the jurisdiction of the Federal District Court for the judicial district in which your address is located (or, if outside the United States, any judicial district in which MiniWebGames.com may be found), and that you will accept service of process from the person who filed the original DMCA notice.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Upon rec<sup></sup>eipt of a valid counter-notice, MiniWebGames.com will forward it to the original complainant. If the complainant does not initiate a court action within <strong>ten (10) business days</strong>, the removed content may be restored at our discretion.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Repeat Infringer Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">In accordance with DMCA § 512(i)(1)(A), MiniWebGames.com maintains a policy of terminating, in appropriate circumstances, the accounts of users who are determined to be repeat infringers. A user who receives <strong>three (3) or more</strong> substantiated copyright infringement notices may have their account suspended or permanently terminated at the sole discretion of MiniWebGames.com. We reserve the right to act sooner in cases of serious or willful infringement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Disclaimer</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This DMCA Policy does not constitute legal advice. MiniWebGames.com recommends consulting a qualified attorney before submitting a takedown notice or counter-notice. The rights and remedies available under the DMCA are in addition to any other rights and remedies available under applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Contact</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">For questions or concerns regarding this policy, please contact:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Email:</strong> thanhlong.bkpro@gmail.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\"><strong>Website:</strong> <a href=\"https://miniwebgames.com\" target=\"_blank\" rel=\"noreferrer noopener\">https://miniwebgames.com</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->','DMCA','','inherit','closed','closed','','82-revision-v1','','','2026-07-08 03:48:45','2026-07-08 03:48:45','',82,'https://miniwebgames.local/?p=237',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (239,1,'2026-07-08 04:18:08','2026-07-08 04:18:08','<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Privacy Policy explains how we collect, use, disclose, and protect your information when you visit <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong> (\"Website\"). By using our Website, you agree to this Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Information We Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may collect the following information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information You Provide</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may voluntarily provide information when you:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Create an account.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Sign in with Google or Facebook.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Contact us through our contact form.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Submit feedback or other requests.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>This information may include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Username</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Profile picture (when using social login)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Messages you send us</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Information Collected Automatically</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>When you visit our Website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Operating system</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Language settings</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Games played</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Referring website</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Date and time of access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cookies and similar technologies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. User Accounts</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Creating an account is optional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Registered users may access additional features such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Favorite Games</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saved preferences</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Personalized experience</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>You are responsible for keeping your account credentials secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Social Login</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You may sign in using supported third-party services, including Google and Facebook.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>When you choose social login, we may receive basic profile information authorized by you, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Profile picture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Unique account identifier</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>We do not receive your password for these services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Your use of social login is also subject to the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Contact Forms</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>When you contact us, we collect the information you choose to provide, including your name, email address, subject, and message.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We use this information only to respond to your inquiry, provide support, and improve our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Cookies</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Measure traffic and usage.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Support advertising services.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>You can manage cookies through your browser settings. Some features may not function properly if cookies are disabled.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>A separate Cookie Policy provides additional details about our use of cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Google Analytics</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use Google Analytics to better understand how visitors use our Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Google Analytics may collect information such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Session duration</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Interactions with the Website</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>This information is used only to analyze traffic, improve user experience, and enhance our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Advertising</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may display advertisements provided by Google AdSense and other advertising partners.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>These partners may use cookies or similar technologies to deliver relevant advertisements, measure campaign performance, and prevent fraud.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You can learn more about Google\'s advertising practices and manage your ad preferences through your Google account.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Third-Party Games</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames offers games developed by us and by third-party developers or publishers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Some games may be embedded from external platforms or use third-party services. These services may collect information according to their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the privacy practices of third-party websites or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Third-Party Services</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may use trusted third-party providers to operate and improve our Website, including services for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Website hosting</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Analytics</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Advertising</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Authentication</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email delivery</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Security</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Customer support</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>These providers may process information only as necessary to perform their services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">10. Data Retention</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We retain personal information only for as long as necessary to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Provide our services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Maintain user accounts</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Respond to inquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Resolve disputes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Enforce our policies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Information that is no longer required may be deleted or anonymized.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">11. International Data Transfers</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Your information may be processed or stored in countries other than your own.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>By using our Website, you understand that your information may be transferred internationally where permitted by applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We take reasonable measures to protect transferred data.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">12. Data Security</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We implement reasonable administrative, technical, and organizational safeguards to protect your information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>However, no method of transmission or electronic storage is completely secure, and we cannot guarantee absolute security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">13. Children\'s Privacy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames is intended for a general audience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We do not knowingly collect personal information from children in violation of applicable laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you believe a child has provided personal information, please contact us. We will take appropriate steps to remove the information when required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">14. Your Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Depending on your location, you may have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Access your personal information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Correct inaccurate information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request deletion of your information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Restrict or object to certain processing.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Withdraw consent where applicable.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request a copy of your personal data.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To exercise these rights, please contact us.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">15. California Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are a California resident, you may have additional rights under applicable California privacy laws, including the right to know, access, delete, and correct certain personal information, subject to legal exceptions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames does not sell personal information as defined by applicable California privacy laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">16. European Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are located in the European Economic Area (EEA), the United Kingdom, or Switzerland, you may have rights under applicable data protection laws, including the GDPR.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Where required, we process personal information based on legal grounds such as your consent, contractual necessity, legal obligations, or our legitimate interests.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">17. Your Choices</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You may:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Update your account information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manage cookies through your browser.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Control advertising preferences through Google.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Stop using our Website at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Contact us to request account deletion where applicable.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">18. Third-Party Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our Website may contain links to third-party websites, games, or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the content, privacy practices, or policies of third-party websites. We encourage you to review their privacy policies before providing any personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">19. Changes to This Privacy Policy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may update this Privacy Policy from time to time to reflect changes in our services, legal requirements, or business practices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The updated version will be posted on this page with a revised <strong>Effective Date</strong>. Your continued use of the Website after any changes constitutes your acceptance of the updated Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">20. Contact Us</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you have any questions about this Privacy Policy or our data practices, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">21. Your Consent</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>By accessing or using MiniWebGames, you acknowledge that you have read and understood this Privacy Policy and agree to the collection, use, and disclosure of your information as described herein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Effective Date</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-07-08 04:18:08','2026-07-08 04:18:08','',3,'https://miniwebgames.local/?p=239',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (241,1,'2026-07-08 04:19:37','2026-07-08 04:19:37','<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Privacy Policy explains how we collect, use, disclose, and protect your information when you visit <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong> (\"Website\"). By using our Website, you agree to this Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Information We Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may collect the following information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information You Provide</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may voluntarily provide information when you:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Create an account.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sign in with Google or Facebook.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us through our contact form.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Submit feedback or other requests.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information may include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Username</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture (when using social login)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Messages you send us</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information Collected Automatically</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you visit our Website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Operating system</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Language settings</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Games played</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Referring website</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Date and time of access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Cookies and similar technologies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. User Accounts</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Creating an account is optional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Registered users may access additional features such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Favorite Games</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Saved preferences</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Personalized experience</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You are responsible for keeping your account credentials secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Social Login</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You may sign in using supported third-party services, including Google and Facebook.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>When you choose social login, we may receive basic profile information authorized by you, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Profile picture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Unique account identifier</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>We do not receive your password for these services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Your use of social login is also subject to the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Contact Forms</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>When you contact us, we collect the information you choose to provide, including your name, email address, subject, and message.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We use this information only to respond to your inquiry, provide support, and improve our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Cookies</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Measure traffic and usage.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Support advertising services.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>You can manage cookies through your browser settings. Some features may not function properly if cookies are disabled.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>A separate Cookie Policy provides additional details about our use of cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Google Analytics</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use Google Analytics to better understand how visitors use our Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Google Analytics may collect information such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Session duration</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Interactions with the Website</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>This information is used only to analyze traffic, improve user experience, and enhance our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Advertising</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may display advertisements provided by Google AdSense and other advertising partners.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>These partners may use cookies or similar technologies to deliver relevant advertisements, measure campaign performance, and prevent fraud.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You can learn more about Google\'s advertising practices and manage your ad preferences through your Google account.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Third-Party Games</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames offers games developed by us and by third-party developers or publishers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Some games may be embedded from external platforms or use third-party services. These services may collect information according to their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the privacy practices of third-party websites or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Third-Party Services</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may use trusted third-party providers to operate and improve our Website, including services for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Website hosting</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Analytics</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Advertising</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Authentication</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email delivery</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Security</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Customer support</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>These providers may process information only as necessary to perform their services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">10. Data Retention</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We retain personal information only for as long as necessary to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Provide our services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Maintain user accounts</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Respond to inquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Resolve disputes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Enforce our policies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Information that is no longer required may be deleted or anonymized.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">11. International Data Transfers</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Your information may be processed or stored in countries other than your own.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>By using our Website, you understand that your information may be transferred internationally where permitted by applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We take reasonable measures to protect transferred data.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">12. Data Security</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We implement reasonable administrative, technical, and organizational safeguards to protect your information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>However, no method of transmission or electronic storage is completely secure, and we cannot guarantee absolute security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">13. Children\'s Privacy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames is intended for a general audience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We do not knowingly collect personal information from children in violation of applicable laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you believe a child has provided personal information, please contact us. We will take appropriate steps to remove the information when required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">14. Your Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Depending on your location, you may have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Access your personal information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Correct inaccurate information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request deletion of your information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Restrict or object to certain processing.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Withdraw consent where applicable.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request a copy of your personal data.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To exercise these rights, please contact us.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">15. California Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are a California resident, you may have additional rights under applicable California privacy laws, including the right to know, access, delete, and correct certain personal information, subject to legal exceptions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames does not sell personal information as defined by applicable California privacy laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">16. European Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are located in the European Economic Area (EEA), the United Kingdom, or Switzerland, you may have rights under applicable data protection laws, including the GDPR.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Where required, we process personal information based on legal grounds such as your consent, contractual necessity, legal obligations, or our legitimate interests.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">17. Your Choices</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You may:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Update your account information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manage cookies through your browser.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Control advertising preferences through Google.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Stop using our Website at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Contact us to request account deletion where applicable.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">18. Third-Party Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our Website may contain links to third-party websites, games, or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the content, privacy practices, or policies of third-party websites. We encourage you to review their privacy policies before providing any personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">19. Changes to This Privacy Policy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may update this Privacy Policy from time to time to reflect changes in our services, legal requirements, or business practices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The updated version will be posted on this page with a revised <strong>Effective Date</strong>. Your continued use of the Website after any changes constitutes your acceptance of the updated Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">20. Contact Us</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you have any questions about this Privacy Policy or our data practices, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">21. Your Consent</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>By accessing or using MiniWebGames, you acknowledge that you have read and understood this Privacy Policy and agree to the collection, use, and disclosure of your information as described herein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Effective Date</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-07-08 04:19:37','2026-07-08 04:19:37','',3,'https://miniwebgames.local/?p=241',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (243,1,'2026-07-08 04:20:23','2026-07-08 04:20:23','<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Privacy Policy explains how we collect, use, disclose, and protect your information when you visit <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong> (\"Website\"). By using our Website, you agree to this Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Information We Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may collect the following information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information You Provide</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may voluntarily provide information when you:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Create an account.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sign in with Google or Facebook.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us through our contact form.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Submit feedback or other requests.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information may include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Username</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture (when using social login)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Messages you send us</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information Collected Automatically</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you visit our Website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Operating system</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Language settings</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Games played</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Referring website</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Date and time of access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Cookies and similar technologies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. User Accounts</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Creating an account is optional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Registered users may access additional features such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Favorite Games</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Saved preferences</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Personalized experience</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You are responsible for keeping your account credentials secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Social Login</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may sign in using supported third-party services, including Google and Facebook.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you choose social login, we may receive basic profile information authorized by you, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Unique account identifier</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not receive your password for these services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your use of social login is also subject to the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Contact Forms</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you contact us, we collect the information you choose to provide, including your name, email address, subject, and message.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use this information only to respond to your inquiry, provide support, and improve our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Measure traffic and usage.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Support advertising services.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can manage cookies through your browser settings. Some features may not function properly if cookies are disabled.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">A separate Cookie Policy provides additional details about our use of cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Google Analytics</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use Google Analytics to better understand how visitors use our Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Google Analytics may collect information such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Session duration</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Interactions with the Website</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>This information is used only to analyze traffic, improve user experience, and enhance our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Advertising</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may display advertisements provided by Google AdSense and other advertising partners.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>These partners may use cookies or similar technologies to deliver relevant advertisements, measure campaign performance, and prevent fraud.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You can learn more about Google\'s advertising practices and manage your ad preferences through your Google account.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Third-Party Games</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames offers games developed by us and by third-party developers or publishers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Some games may be embedded from external platforms or use third-party services. These services may collect information according to their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the privacy practices of third-party websites or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Third-Party Services</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may use trusted third-party providers to operate and improve our Website, including services for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Website hosting</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Analytics</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Advertising</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Authentication</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email delivery</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Security</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Customer support</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>These providers may process information only as necessary to perform their services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">10. Data Retention</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We retain personal information only for as long as necessary to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Provide our services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Maintain user accounts</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Respond to inquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Resolve disputes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Enforce our policies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Information that is no longer required may be deleted or anonymized.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">11. International Data Transfers</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Your information may be processed or stored in countries other than your own.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>By using our Website, you understand that your information may be transferred internationally where permitted by applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We take reasonable measures to protect transferred data.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">12. Data Security</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We implement reasonable administrative, technical, and organizational safeguards to protect your information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>However, no method of transmission or electronic storage is completely secure, and we cannot guarantee absolute security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">13. Children\'s Privacy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames is intended for a general audience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We do not knowingly collect personal information from children in violation of applicable laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you believe a child has provided personal information, please contact us. We will take appropriate steps to remove the information when required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">14. Your Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Depending on your location, you may have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Access your personal information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Correct inaccurate information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request deletion of your information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Restrict or object to certain processing.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Withdraw consent where applicable.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request a copy of your personal data.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To exercise these rights, please contact us.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">15. California Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are a California resident, you may have additional rights under applicable California privacy laws, including the right to know, access, delete, and correct certain personal information, subject to legal exceptions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>MiniWebGames does not sell personal information as defined by applicable California privacy laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">16. European Privacy Rights</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you are located in the European Economic Area (EEA), the United Kingdom, or Switzerland, you may have rights under applicable data protection laws, including the GDPR.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Where required, we process personal information based on legal grounds such as your consent, contractual necessity, legal obligations, or our legitimate interests.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">17. Your Choices</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You may:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Update your account information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manage cookies through your browser.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Control advertising preferences through Google.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Stop using our Website at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Contact us to request account deletion where applicable.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">18. Third-Party Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our Website may contain links to third-party websites, games, or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are not responsible for the content, privacy practices, or policies of third-party websites. We encourage you to review their privacy policies before providing any personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">19. Changes to This Privacy Policy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may update this Privacy Policy from time to time to reflect changes in our services, legal requirements, or business practices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The updated version will be posted on this page with a revised <strong>Effective Date</strong>. Your continued use of the Website after any changes constitutes your acceptance of the updated Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">20. Contact Us</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you have any questions about this Privacy Policy or our data practices, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">21. Your Consent</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>By accessing or using MiniWebGames, you acknowledge that you have read and understood this Privacy Policy and agree to the collection, use, and disclosure of your information as described herein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Effective Date</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-07-08 04:20:23','2026-07-08 04:20:23','',3,'https://miniwebgames.local/?p=243',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (245,1,'2026-07-08 04:23:23','2026-07-08 04:23:23','<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Privacy Policy explains how we collect, use, disclose, and protect your information when you visit <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong> (\"Website\"). By using our Website, you agree to this Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Information We Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may collect the following information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information You Provide</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may voluntarily provide information when you:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Create an account.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sign in with Google or Facebook.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us through our contact form.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Submit feedback or other requests.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information may include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Username</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture (when using social login)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Messages you send us</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information Collected Automatically</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you visit our Website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Operating system</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Language settings</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Games played</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Referring website</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Date and time of access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Cookies and similar technologies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. User Accounts</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Creating an account is optional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Registered users may access additional features such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Favorite Games</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Saved preferences</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Personalized experience</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You are responsible for keeping your account credentials secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Social Login</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may sign in using supported third-party services, including Google and Facebook.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you choose social login, we may receive basic profile information authorized by you, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Unique account identifier</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not receive your password for these services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your use of social login is also subject to the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Contact Forms</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you contact us, we collect the information you choose to provide, including your name, email address, subject, and message.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use this information only to respond to your inquiry, provide support, and improve our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Measure traffic and usage.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Support advertising services.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can manage cookies through your browser settings. Some features may not function properly if cookies are disabled.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">A separate Cookie Policy provides additional details about our use of cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">6. Google Analytics</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use Google Analytics to better understand how visitors use our Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Google Analytics may collect information such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Session duration</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Interactions with the Website</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information is used only to analyze traffic, improve user experience, and enhance our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">7. Advertising</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may display advertisements provided by Google AdSense and other advertising partners.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These partners may use cookies or similar technologies to deliver relevant advertisements, measure campaign performance, and prevent fraud.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can learn more about Google\'s advertising practices and manage your ad preferences through your Google account.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">8. Third-Party Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames offers games developed by us and by third-party developers or publishers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Some games may be embedded from external platforms or use third-party services. These services may collect information according to their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We are not responsible for the privacy practices of third-party websites or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">9. Third-Party Services</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may use trusted third-party providers to operate and improve our Website, including services for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Website hosting</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Analytics</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Advertising</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Authentication</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email delivery</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Security</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Customer support</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These providers may process information only as necessary to perform their services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">10. Data Retention</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We retain personal information only for as long as necessary to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Provide our services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Maintain user accounts</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Respond to inquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Resolve disputes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Enforce our policies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Information that is no longer required may be deleted or anonymized.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">11. International Data Transfers</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your information may be processed or stored in countries other than your own.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By using our Website, you understand that your information may be transferred internationally where permitted by applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We take reasonable measures to protect transferred data.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">12. Data Security</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We implement reasonable administrative, technical, and organizational safeguards to protect your information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">However, no method of transmission or electronic storage is completely secure, and we cannot guarantee absolute security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">13. Children\'s Privacy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames is intended for a general audience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not knowingly collect personal information from children in violation of applicable laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you believe a child has provided personal information, please contact us. We will take appropriate steps to remove the information when required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">14. Your Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Depending on your location, you may have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Access your personal information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Correct inaccurate information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Request deletion of your information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Restrict or object to certain processing.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Withdraw consent where applicable.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Request a copy of your personal data.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">To exercise these rights, please contact us.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">15. California Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you are a California resident, you may have additional rights under applicable California privacy laws, including the right to know, access, delete, and correct certain personal information, subject to legal exceptions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames does not sell personal information as defined by applicable California privacy laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">16. European Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you are located in the European Economic Area (EEA), the United Kingdom, or Switzerland, you may have rights under applicable data protection laws, including the GDPR.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Where required, we process personal information based on legal grounds such as your consent, contractual necessity, legal obligations, or our legitimate interests.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">17. Your Choices</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Update your account information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Manage cookies through your browser.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Control advertising preferences through Google.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Stop using our Website at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us to request account deletion where applicable.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">18. Third-Party Links</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Our Website may contain links to third-party websites, games, or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We are not responsible for the content, privacy practices, or policies of third-party websites. We encourage you to review their privacy policies before providing any personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">19. Changes to This Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may update this Privacy Policy from time to time to reflect changes in our services, legal requirements, or business practices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The updated version will be posted on this page with a revised <strong>Effective Date</strong>. Your continued use of the Website after any changes constitutes your acceptance of the updated Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">20. Contact Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you have any questions about this Privacy Policy or our data practices, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">21. Your Consent</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By accessing or using MiniWebGames, you acknowledge that you have read and understood this Privacy Policy and agree to the collection, use, and disclosure of your information as described herein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Effective Date</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-07-08 04:23:23','2026-07-08 04:23:23','',3,'https://miniwebgames.local/?p=245',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (246,1,'2026-07-08 04:23:41','2026-07-08 04:23:41','<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h5>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Privacy Policy explains how we collect, use, disclose, and protect your information when you visit <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong> (\"Website\"). By using our Website, you agree to this Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Information We Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may collect the following information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information You Provide</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may voluntarily provide information when you:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Create an account.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Sign in with Google or Facebook.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us through our contact form.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Submit feedback or other requests.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information may include:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Username</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture (when using social login)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Messages you send us</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Information Collected Automatically</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you visit our Website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Operating system</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Language settings</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Games played</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Referring website</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Date and time of access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Cookies and similar technologies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. User Accounts</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Creating an account is optional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Registered users may access additional features such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Favorite Games</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Saved preferences</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Personalized experience</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You are responsible for keeping your account credentials secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Social Login</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may sign in using supported third-party services, including Google and Facebook.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you choose social login, we may receive basic profile information authorized by you, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Profile picture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Unique account identifier</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not receive your password for these services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your use of social login is also subject to the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Contact Forms</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">When you contact us, we collect the information you choose to provide, including your name, email address, subject, and message.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use this information only to respond to your inquiry, provide support, and improve our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Measure traffic and usage.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Support advertising services.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can manage cookies through your browser settings. Some features may not function properly if cookies are disabled.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">A separate Cookie Policy provides additional details about our use of cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">6. Google Analytics</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use Google Analytics to better understand how visitors use our Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Google Analytics may collect information such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Browser type</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Session duration</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Interactions with the Website</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">This information is used only to analyze traffic, improve user experience, and enhance our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">7. Advertising</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may display advertisements provided by Google AdSense and other advertising partners.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These partners may use cookies or similar technologies to deliver relevant advertisements, measure campaign performance, and prevent fraud.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You can learn more about Google\'s advertising practices and manage your ad preferences through your Google account.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">8. Third-Party Games</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames offers games developed by us and by third-party developers or publishers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Some games may be embedded from external platforms or use third-party services. These services may collect information according to their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We are not responsible for the privacy practices of third-party websites or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">9. Third-Party Services</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may use trusted third-party providers to operate and improve our Website, including services for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Website hosting</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Analytics</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Advertising</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Authentication</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Email delivery</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Security</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Customer support</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These providers may process information only as necessary to perform their services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">10. Data Retention</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We retain personal information only for as long as necessary to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Provide our services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Maintain user accounts</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Respond to inquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Resolve disputes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Enforce our policies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Information that is no longer required may be deleted or anonymized.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">11. International Data Transfers</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Your information may be processed or stored in countries other than your own.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By using our Website, you understand that your information may be transferred internationally where permitted by applicable law.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We take reasonable measures to protect transferred data.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">12. Data Security</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We implement reasonable administrative, technical, and organizational safeguards to protect your information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">However, no method of transmission or electronic storage is completely secure, and we cannot guarantee absolute security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">13. Children\'s Privacy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames is intended for a general audience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not knowingly collect personal information from children in violation of applicable laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you believe a child has provided personal information, please contact us. We will take appropriate steps to remove the information when required.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">14. Your Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Depending on your location, you may have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Access your personal information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Correct inaccurate information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Request deletion of your information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Restrict or object to certain processing.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Withdraw consent where applicable.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Request a copy of your personal data.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">To exercise these rights, please contact us.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">15. California Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you are a California resident, you may have additional rights under applicable California privacy laws, including the right to know, access, delete, and correct certain personal information, subject to legal exceptions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">MiniWebGames does not sell personal information as defined by applicable California privacy laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">16. European Privacy Rights</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you are located in the European Economic Area (EEA), the United Kingdom, or Switzerland, you may have rights under applicable data protection laws, including the GDPR.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Where required, we process personal information based on legal grounds such as your consent, contractual necessity, legal obligations, or our legitimate interests.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">17. Your Choices</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">You may:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Update your account information.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Manage cookies through your browser.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Control advertising preferences through Google.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Stop using our Website at any time.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Contact us to request account deletion where applicable.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">18. Third-Party Links</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Our Website may contain links to third-party websites, games, or services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We are not responsible for the content, privacy practices, or policies of third-party websites. We encourage you to review their privacy policies before providing any personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">19. Changes to This Privacy Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may update this Privacy Policy from time to time to reflect changes in our services, legal requirements, or business practices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">The updated version will be posted on this page with a revised <strong>Effective Date</strong>. Your continued use of the Website after any changes constitutes your acceptance of the updated Privacy Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">20. Contact Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you have any questions about this Privacy Policy or our data practices, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">21. Your Consent</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By accessing or using MiniWebGames, you acknowledge that you have read and understood this Privacy Policy and agree to the collection, use, and disclosure of your information as described herein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Effective Date</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-07-08 04:23:41','2026-07-08 04:23:41','',3,'https://miniwebgames.local/?p=246',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (248,1,'2026-07-08 04:28:40','2026-07-08 04:28:40','<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Effective Date:</strong> July 8, 2026</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Welcome to <strong>MiniWebGames</strong> (\"we,\" \"our,\" or \"us\"). This Cookie Policy explains how we use cookies and similar technologies on <strong><a href=\"https://miniwebgames.com\">https://miniwebgames.com</a></strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">By using our Website, you agree to our use of cookies as described in this Policy.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. What Are Cookies?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Cookies are small text files stored on your device when you visit a website. They help websites function properly, remember your preferences, improve performance, and support analytics and advertising.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. How We Use Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use cookies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Keep you signed in.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Remember your preferences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Save favorite games.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Improve website performance.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Measure website traffic.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Detect security issues.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"small\"} -->\n<li class=\"has-small-font-size\">Deliver and measure advertisements.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Types of Cookies We Use</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Essential Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These cookies are required for the Website to function properly, including user authentication, account management, and security.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Preference Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These cookies remember your settings and preferences to improve your browsing experience.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Analytics Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We use Google Analytics to understand how visitors interact with our Website and improve our content and services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Advertising Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may use Google AdSense and other advertising partners to display relevant advertisements and measure advertising performance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">These providers may use cookies or similar technologies in accordance with their own privacy policies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Third-Party Cookies</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Some games, embedded content, social login services, and other third-party features may set their own cookies.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We do not control these cookies and recommend reviewing the privacy policies of the respective providers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Managing Cookies</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Most web browsers allow you to manage, block, or delete cookies through browser settings.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Disabling certain cookies may affect some features of the Website.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Updates to This Policy</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">We may update this Cookie Policy from time to time.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Any changes will be posted on this page with a revised <strong>Effective Date</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">6. Contact Us</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">If you have any questions about this Cookie Policy, please contact us through our <strong>Contact Us</strong> page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Website:</strong> MiniWebGames</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Contact Page:</strong> <a>https://miniwebgames.com/contact-us</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Effective Date:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\"><strong>Last Updated:</strong> July 8, 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Cookie Policy','','inherit','closed','closed','','80-revision-v1','','','2026-07-08 04:28:40','2026-07-08 04:28:40','',80,'https://miniwebgames.local/?p=248',0,'revision','',0);
